6QGo6OjZALnAjNDQuYCMxNDNg&&bt=1533&ft=ERfCkaZWD03Q12NvsooHzIxRSfYFpq_45SY&mime_type=video_mp4&rc=Njg8M2VoaDo2NWc8OjxoOkBpanlzNmw5cnk2OTMzODczNEAzLmJjYmMwXjMxMWJhXjAwYSMwaF5hMmQ0cmphLS1kMWBzcw%3D%3D&vvpl=1&l=202606262302466E5E157D382C1691D36D&btag=e00090000", "download_url": "https://api16-normal-no1a.tiktokv.eu/aweme/v1/play/?video_id=v1c044g50000d6m3uv7og65id3apkv3g&line=0&watermark=0&logo_name=tiktok_m&source=SEARCH&file_id=373ea9d7e94d4263a73efeebf0e91563&item_id=7614531011816279317&signaturev3=dmlkZW9faWQ7ZmlsZV9pZDtpdGVtX2lkLjcwNWI5YzMwZjk4NDBkZDc0MWQzMGNkZmFlNzNkOTAx&shp=d05b14bd&shcp=-"}, "music": {"id": "7614531061954939664", "title": "original sound - _n_a_t_a_l_i_j_", "author": "💠ЧІЧКА💠", "original": true, "play_url": "https://sf16-ies-music-sg.tiktokcdn.com/obj/tiktok-obj/7614531065803049745.mp3"}, "hashtags": ["лайфхак", "ніколинеробицього", "добро", "приколи", "українськийтікток"], "metadata_source": "tikwm", "search_query": "жодних"}
{"source_url": "https://www.tiktok.com/@andriy_kozyura/video/7655718262897954068", "scraped_at": "2026-06-26T23:02:47.764759+00:00", "id": "7655718262897954068", "description": "10 місяців на позиціях без одежі і їжі… Чи здорова ситуація коли хлопці сидять на позиціях понад 10 місяців без жодних ротацій. Щось напевно не так, коли командування тобі каже: вам доставити їжу чи зимову форму. Щось не так, коли ти вимушений мародерити і вдягати жіночі речі, щоб не замерзнути взимку. Точно не так, коли твоєму командуванню на тебе глибоко по@ер і ти думаєш як просто вижити на нулі. І це все знову про 14 бригаду, яку військові між собою називають мʼясною. Змінили за час повномасштабки, вже 5 комбрига, але нажаль від перестановки командування ситуація не змінилась… З 15 вересня 2025 року Романюк Дмитро зайшов на позиції під Купʼянськом. З 22 березня 2026 року з ним відсутній будь-який зв'язок. Після втрати зв'язку командування двічі передавало родині записи його голосу по рації, що давало надію, що він живий. Проте вже понад три місяці вони не мають жодної достовірної інформації про його стан та місцезнаходження. Разом з Дмитром там ще 5 наших хлопців. Щось напевно не так, у нас з реформою армії або адекватністю командування…  Чому не виконується Наказ Олександра Сирського про обовʼязкові ротації?  Коли ми почнемо поважати своїх бійців, а не ставитись як до штатної одиниці або живого мʼяса. Як збираємось вигравати цю війну, проводити мобілізацію та вирішувати ЗСЧ, коли існують такі факти. Коли зміняться підходи, принципи і відношення до простих бійців?    Нажаль такі кричущі випадки є не поодинокими в ЗСУ, тому за дорученням родини Дмитра Романюка та від Спілки ветеранів російсько-украніськоі війни звертаюсь до: Командування 14 бригада Олександр Сирський Ольга Решетилова Михайло Федоров Руслан Приходько Дмитро Лубінець Міністерство ветеранської політики Офіс президента України Президент України Негайно відреагувати на цю ситуацію та забезпечити ротацію воїнів, які вже 10 місяців поспіль перебувають на бойових позиціях із подальшою реабілітацією та відновлення військових. ", "created_at": 1782485816, "author": {"id": "7209722319428977670", "unique_id": "andriy_kozyura", "nickname": "АК", "verified": null, "signature": null, "followers": null, "following": null, "likes": null, "videos": null}, "stats": {"plays": 1830, "likes": 44, "comments": 3, "shares": 2, "saves": 3}, "video": {"duration": 192, "ratio": null, "cover": "https://p16-common-sign.tiktokcdn-eu.com/tos-alisg-p-0037/oUjqXXLpoAH2HRwDgQFiPkUDmfmL80pEBEBBeQ~tplv-tiktokx-origin.image?biz_tag=musically_video.video_cover&dr=1347&idc=no1a&ps=933b5bde&refresh_token=c4c25f56&s=SEARCH&sc=cover&shcp=c1333099&shp=d05b14bd&t=bacd0480&x-expires=1782601200&x-signature=0RY0hM4ejaaLHK7Vgo1Ml%2BvpbW4%3D", "dynamic_cover": "https://p16-common-sign.tiktokcdn-eu.com/tos-alisg-p-0037/oIqiUYejmBLQpAFR2B8Qm0WElPEpgZfxmLkDEi~tplv-tiktokx-origin.image?dr=9229&refresh_token=4e8b8777&x-expires=1782601200&x-signature=ZqV4dj0TZ2LTuo8yZbOKF09Fw%2Bg%3D&t=bacd0480&ps=4f5296ae&shp=d05b14bd&shcp=c1333099&idc=no1a&biz_tag=tt_video&s=SEARCH&sc=dynamic_cover", "origin_cover": "https://p16-common-sign.tiktokcdn-eu.com/tos-alisg-p-0037/oAfGTXoNFJGXINHRLSAhfggG9A7Qfl4FESespt~tplv-tiktokx-shrink-aq:360:360:q75.jpeg?dr=13023&refresh_token=1925dc04&x-expires=1782601200&x-signature=CnyTQ5qnYTI%2BGLSXFG8lS1RB%2BS4%3D&t=bacd0480&ps=d97f9a4f&shp=d05b14bd&shcp=c1333099&idc=no1a&s=SEARCH&sc=feed_cover&biz_tag=tt_video", "play_url": "https://v19.tiktokcdn-eu.com/5ea0da07c148a4b0814e0d297b66eb4d/6a405757/video/tos/alisg/tos-alisg-pve-0037c001/ogms9A8HpUgfpEIqJPFfBBgCLJW0LiQjRMD2Em/?a=1233&bti=NEBzNTY6QGo6OjZALnAjNDQuYCMxNDNg&&bt=272&ft=ERfCkaZWD03Q12NvsooHzIxRSfYFpq_45SY&mime_type=video_mp4&rc=NDVoaTppNjg1ZjQ6ZDk3OUBpajhtdnU5cnM8OzMzODczNEAvNWFhXzY0NjQxYTUxNF8xYSNscG41MmRrMnNhLS1kMTFzcw%3D%3D&vvpl=1&l=202606262302466E5E157D382C1691D36D&btag=e00090000", "download_url": "https://api16-normal-no1a.tiktokv.eu/aweme/v1/play/?video_